MERGE INTO CONSULTAS FIN USING (SELECT '900013MetaProducto' INFORME ,TO_CLOB(q'[SELECT  V_SOLICITUD_CDP.DESCRIPCION_METAPRODUCTO DESCRIPCION_METAPRODUCT,
FUENTE_RECURSOS.NOMBRE AS FUENTE
FROM V_SOLICITUD_CDP
  INNER JOIN  PLAN_PRESUPUESTAL
    ON V_SOLICITUD_CDP.COMPANIA           = PLAN_PRESUPUESTAL.COMPANIA
    AND V_SOLICITUD_CDP.ANORUBRO          = PLAN_PRESUPUESTAL.ANO
    AND V_SOLICITUD_CDP.RUBRO             = PLAN_PRESUPUESTAL.CODIGO   
    INNER JOIN FUENTE_RECURSOS
    ON V_SOLICITUD_CDP.COMPANIA         = FUENTE_RECURSOS.COMPANIA 
    AND V_SOLICITUD_CDP.VIGENCIA         = FUENTE_RECURSOS.ANO
   AND V_SOLICITUD_CDP.FUENTERECURSOS        = FUENTE_RECURSOS.CODIGO
 WHERE V_SOLICITUD_CDP.COMPANIA      = '$P!{PR_COMPANIA}' 
  AND  V_SOLICITUD_CDP.TIPOT        = '$P!{PR_TIPOT}'
  AND V_SOLICITUD_CDP.CLASET        = '$P!{PR_CLASET}' 
  AND V_SOLICITUD_CDP.CONSECUTIVO   = $P!{PR_CONSECUTIVO} 
  AND V_SOLICITUD_CDP.DEPENDENCIA   = '$P!{PR_DEPENDENCIA}'
  GROUP BY V_SOLICITUD_CDP.DESCRIPCION_METAPRODUCTO , 
  FUENTE_RECURSOS.NOMBRE]') CONSULTA, 6 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);

MERGE INTO CONSULTAS_SUB FIN USING (SELECT '002450SolicitudCDPHonda' INFORME_PADRE, '900013MetaProducto' INFORME_HIJO, 'PR_STRSQL_SUB_METAPRODUCTO' PARAMETRO ,'JCROJAS' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (FIN.INFORME_PADRE = INI.INFORME_PADRE AND INI.INFORME_HIJO = FIN.INFORME_HIJO)  WHEN MATCHED THEN  UPDATE SET FIN.PARAMETRO = INI.PARAMETRO , FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME_PADRE,INFORME_HIJO, PARAMETRO,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME_PADRE,INI.INFORME_HIJO, INI.PARAMETRO,INI.CREATED_BY,SYSDATE);
